head.script:

scwin.repalStatus = "C";
scwin.repFileStr = [];

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 */
scwin.initScreen = function() {
	$p.$("#qnaMmodify").click(function() {
		$("table.creat").removeClass("table-on");
		$("table.view").removeClass("table-on");
		$("table.creat").addClass("table-on");
	});
	$p.$("#btn_qnaCreate").click(function() {
		scwin.btnQnaAdd_onclick();
		$("table.mody").removeClass("table-on");
		$("table.creat").addClass("table-on");
		$("table.view").removeClass("table-on");
	});
	$(".pop").click(function() {
		$(this).toggleClass("pop-on","pop-off");

		$(".re-list").toggleClass("full-on");
		$(".lists.re-li").toggleClass("full-on");
		$(".re-t").toggleClass("full-on");

		if ($(this)["0"].classList[2] == "pop-on") {
			$p.$("#grpNttQnaRepla").mCustomScrollbar().css("height",parseInt($(".nav-board").css("height").replace("px", "")) - 150);
		} else {
			$p.$("#grpNttQnaRepla").mCustomScrollbar().css("height",parseInt($(".nav-board").css("height").replace("px", "")) - 700);
		}
	//$p.$("#grpNttQnaRepla").mCustomScrollbar().css("height",parseInt($(".nav-board").css("height").replace("px", "")) - 150);
	});
	$(".nav-title-group .close").click(function() {
		$(".nav-board").removeClass("board-on");
		comLib.removeSrc();
	});
	$p.$("#qnaTrash").click(function() {
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.deleteQnaLeft");
	});
	$p.$("#btnCancel").click(function() {
		if (dmaNttMt.get("rowStatus") == "C") {
			$("table.creat").removeClass("table-on");
			$("table.view").removeClass("table-on");
		} else {
			$("table.creat").removeClass("table-on");
			$("table.view").addClass("table-on");
		}
	});
};

scwin.selectQna = function(nttQnaNo) {
	saveQnaNttNo = nttQnaNo;
	var dltQnaListJson = dltQnaList.getMatchedJSON("nttNo", saveQnaNttNo, true, 0, dltQnaList.getRowCount());
	//reListId.hide();
	$("table.creat").removeClass("table-on");
	$("table.view.repla").addClass("table-on");

	utilLib.clearDcObj(dmaQnaMt);

	dmaQnaMt.set("rowStatus", "U");
	dmaQnaMt.set("nttNo", dltQnaListJson[0].nttNo);
	dmaQnaMt.set("bbsId", dltQnaListJson[0].bbsId);
	dmaQnaMt.set("sysDivCd", dltQnaListJson[0].sysDivCd);
	dmaQnaMt.set("ctgryId", dltQnaListJson[0].ctgryId);
	dmaQnaMt.set("ntceLocgovCd", dltQnaListJson[0].ntceLocgovCd);
	dmaQnaMt.set("nttClsCd1", dltQnaListJson[0].nttClsCd1);
	dmaQnaMt.set("nttClsCd2", dltQnaListJson[0].nttClsCd2);
	dmaQnaMt.set("nttStatCd", dltQnaListJson[0].nttStatCd);
	dmaQnaMt.set("nttTit", dltQnaListJson[0].nttTit);
	dmaQnaMt.set("nttCtnt", dltQnaListJson[0].nttCtnt);
	dmaQnaMt.set("nttPwdno", dltQnaListJson[0].nttPwdno);
	dmaQnaMt.set("nttRdcnt", dltQnaListJson[0].nttRdcnt);
	dmaQnaMt.set("nttNtfFnctYn", dltQnaListJson[0].nttNtfFnctYn);
	dmaQnaMt.set("ntfStrtDe", dltQnaListJson[0].ntfStrtDe);
	dmaQnaMt.set("ntfEndDe", dltQnaListJson[0].ntfEndDe);
	dmaQnaMt.set("answerYn", dltQnaListJson[0].answerYn);
	dmaQnaMt.set("priorNttYn", dltQnaListJson[0].priorNttYn);
	dmaQnaMt.set("atchflId", dltQnaListJson[0].atchflId);
	dmaQnaMt.set("useYn", dltQnaListJson[0].useYn);
	dmaQnaMt.set("sortOrdr", dltQnaListJson[0].sortOrdr);
	dmaQnaMt.set("lastUpdtDt", dltQnaListJson[0].frstRegistDt);
	dmaQnaMt.set("frstRgstrId", dltQnaListJson[0].frstRgstrId);

	if (dltQnaListJson[0].frstRgstrId != comLib.getUsrId()) {
		qnaMmodify.hide();
		qnaTrash.hide();
	} else {
		qnaMmodify.show("inline-block");
		qnaTrash.show("inline-block");
	}

	//scwin.updateNttRdcnt();

	qnaUser.setLabel(dltQnaListJson[0].korname+" / "+dltQnaListJson[0].posit+" / " + dltQnaListJson[0].dept);
	qnaDay.setLabel(dltQnaListJson[0].lastUpdtDt);
	viewFileQna.render.innerHTML = ""; 
	var dltQnaJson = dltQnaReplaList.getMatchedJSON("parntsNttNo", dltQnaListJson[0].nttNo, true, 0, dltQnaReplaList.getRowCount());
	var str = [];
	var repFile =[];
	if (dltQnaJson.length > 0) {
		for(var i=0;i<dltQnaJson.length;i++) {
			str.push("<div class=\"w2group re-g\">");
			str.push("<div class=\"w2group user\">");
			str.push("<span class=\"w2span ac\">A</span>");
			str.push("<span class=\"w2span name\">"+dltQnaJson[i].korname+" ㅣ "+dltQnaJson[i].dept+" ㅣ " + dltQnaJson[i].posit+"</span>");
			str.push("<span class=\"w2span day\">"+dltQnaJson[i].frstRegistDt+"</span>");
			if (comLib.getUsrId() == dltQnaJson[i].frstRgstrId) {
				str.push("<div class=\"w2group btn-group\">");
				str.push("<a class=\"w2anchor2 modify\" href=\"javascript:" + comLib.getFrameId($p) + "scwin.detailsQnaRepla('"+dltQnaJson[i].nttNo+"');\">수정</a>");
				str.push("<a class=\"w2anchor2 trash\" href=\"javascript:" + comLib.getFrameId($p) + "scwin.deleteQnaRepla('"+dltQnaJson[i].nttNo+"');\">삭제</a>");
				str.push("</div>");
			}
			str.push("</div>");
			str.push("<div class=\"w2group view-txt\">");
			str.push("<span class=\"w2span \">"+dltQnaJson[i].nttCtnt+"</span>");
			str.push("</div>");
			str.push("<div class=\"w2group view-file\" id=\"repFile_"+dltQnaJson[i].atchflId+"\">");
			if (dltQnaJson[i].atchflId !="") {
				repFile.push(dltQnaJson[i].atchflId);
			}
			//str.push("<a class=\"w2anchor2 \" href=\"javascript:void(null);\">"+dltQnaJson[i].atchflId+"</a>");
			str.push("</div>");
			str.push("</div>");
		}
		replaArea.render.innerHTML = str.join(""); 
	} else {
		replaArea.render.innerHTML = ""; 
	}
	utilLib.clearDcObj(qnaAtchfl.getWindow()._dltNttFile);
	if (dltQnaListJson[0].atchflId != null && dltQnaListJson[0].atchflId != "") {
		var requestData = {};
		requestData.dmaFileBasic = {atchflId : dltQnaListJson[0].atchflId };
		var option = {
			action : "sc/file/fileList.do",
			reqData : requestData,
			resData : qnaAtchfl.getWindow()._dltNttFile,
			success : "scwin.searchQnaMtCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	} else {
		qnaAtchfl.getWindow()._dltNttFile.deleteRow(0);
	}

	if (repFile.length > 0) {
		scwin.replaFile(repFile);
	}
};

scwin.replaFile = function(repFile) {
	dltRepalFileList.setData(repFile, false, ["atchflId"]);
	var requestData = {};
	repFileStr = repFile;
	requestData.data = dltRepalFileList.getAllJSON();
	var option = {
		action : "sc/file/replaFileList.do",
		reqData : requestData,
		resData : "",
		success : "scwin.replaFileCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.replaFileCallback = function(resBody) {
	if (resBody.message.code == 'success') {
		utilLib.clearDcObj(dltRepalFileList);
		dltRepalFileList.setJSON(resBody.message.data, true); // append data
		if (dltRepalFileList.getRowCount() > 0) {
			for(var y=0; y<scwin.repFileStr.length; y++) {
				var str = [];
				for(var i=0;i<dltRepalFileList.getRowCount();i++) {
					if (scwin.repFileStr[y] == dltRepalFileList.getCellData(i, "atchflId")) {
						str.push("<a href=\"javascript:" + comLib.getFrameId($p) + "scwin.fileQnaDownload('"+dltRepalFileList.getCellData(i, "atchflId")+"','"+dltRepalFileList.getCellData(i, "fileSeq")+"');\" class='w2anchor2 '>");
						str.push(dltRepalFileList.getCellData(i, "orginlFileNm"));
						str.push("</a>");
					}
				}
				$p.$("#repFile_"+scwin.repFileStr[y]).html(str.join(""));
			}
		}
	} else {
		alert("fail");
	}
	scwin.repFileStr = [];
};

/**
 * 조회 콜백 함수
 * @param
 * @return
 */
scwin.searchQnaMtCallback = function(resBody) {
	if (resBody.message.code == 'success') {
		if (qnaAtchfl.getWindow()._dltNttFile.getRowCount() > 0) {
			var str = [];
			for(var i=0;i<qnaAtchfl.getWindow()._dltNttFile.getRowCount();i++) {
				str.push("<a href=\"javascript:" + comLib.getFrameId($p) + "scwin.fileQnaDownload('"+qnaAtchfl.getWindow()._dltNttFile.getCellData(i, "atchflId")+"','"+qnaAtchfl.getWindow()._dltNttFile.getCellData(i, "fileSeq")+"');\" class='w2anchor2 '>");
				str.push(qnaAtchfl.getWindow()._dltNttFile.getCellData(i, "orginlFileNm"));
				str.push("</a>");
			}
			viewFileQna.render.innerHTML = str.join(""); 
		} else {
			viewFileQna.render.innerHTML = ""; 
		}
	} else {
		alert("fail");
	}
};

scwin.btnQnaSave_onclick_onclick = function() {
	// 입력값 셋팅
	if (qnaAtchfl.getWindow()._mpdNttMultiAtchFile.getFileCount() > 0) {
		qnaAtchfl.getWindow()._mpdNttMultiAtchFile.startUpload();
	} else {
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveNttConfirmCallback");
	}
};

/**
 * 저장처리
 */
scwin.saveNttConfirmCallback = function() {
	var requestData = {};
	requestData.data = dmaQnaMt.getJSON();
	requestData.data1 = qnaAtchfl.getWindow()._dltNttFile.getModifiedJSON();
	var option = {
		action : "sc/ntt/saveNtt.do",
		reqData : requestData,
		resData : dltQnaList,
		success : "scwin.saveQnaInsertCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.saveQnaInsertCallback = function(resBody) {
	comLib.NTT_NO = resBody.message.data;
	utilLib.clearDcObj(dltQnaList);
	utilLib.clearDcObj(dltQnaReplaList);
	//scwin.choiseQna(txtQnaNo.getValue() ,parseInt(txtCnt.getValue())+1);
	scwin.choiseQna(txtQnaNo.getValue() ,txtCnt.getValue());
}; 

scwin.saveQnaCallback = function(resBody) {
	comLib.NTT_NO = resBody.message.data;
	utilLib.clearDcObj(dltQnaList);
	utilLib.clearDcObj(dltQnaReplaList);
	scwin.choiseQna(txtQnaNo.getValue() ,txtCnt.getValue());
};

//scwin.saveCallback
//저장 후 게시물 목록
scwin.choiseQna = function(bbsId, cnt) {
	btnSaveRepal.show("inline-block");
	btnUpdateRepal.hide();

	$("table.creat").removeClass("table-on");
	$("table.view").removeClass("table-on");
	utilLib.clearDcObj(dmaQnaMt);

	var dltQnaMngJson = dltQnaMng.getMatchedJSON("bbsId", bbsId, true, 0, dltQnaMng.getRowCount());

	if (dltQnaMngJson.length > 0) {
		var nttTit = "";
		var korname = "";

		if (sbxSearchTyCd.getValue() == "01") {
			nttTit = inputNttSearch.getValue();
		}
		if (sbxSearchTyCd.getValue() == "02") {
			korname = inputNttSearch.getValue();
		}

		dmaQnaMt.set("bbsId", dltQnaMngJson[0].bbsId);
		dmaQnaMt.set("sysDivCd", dltQnaMngJson[0].sysDivCd);
		var requestData = {};

		if (cnt < comLib.PAGE_QNA_SIZE) {
			cnt = comLib.PAGE_QNA_SIZE;
		}
		requestData.data = {bbsId:dltQnaMngJson[0].bbsId ,"nttTit" : nttTit,"korname" : korname, rnum:0 ,totalCount : cnt - comLib.PAGE_QNA_SIZE, pageSize : comLib.PAGE_QNA_SIZE};

		var option = {
			action : "sc/ntt/retrieveQnaNtt.do",
			reqData : requestData,
			resData : "",
			success : "comLib.choiseQnaCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	}
};

scwin.btnQnaAdd_onclick = function() {
	utilLib.clearDcObj(qnaAtchfl.getWindow()._dltNttFile);

	var nttClsCd1 = dmaQnaMt.get("nttClsCd1");
	var bbsId = 	dmaQnaMt.get("bbsId");
	var sysDivCd = 	dmaQnaMt.get("sysDivCd");

	if (bbsId == '') {
		nttClsCd1 = dltQnaMng.getCellData(0, "nttClsCd1")
		bbsId = 	dltQnaMng.getCellData(0, "bbsId")
		sysDivCd = 	dltQnaMng.getCellData(0, "sysDivCd")
	}

	utilLib.clearDcObj(dmaQnaMt);
	dmaQnaMt.set("rowStatus", "C");
	dmaQnaMt.set("nttClsCd1", nttClsCd1);
	dmaQnaMt.set("bbsId", bbsId);
	dmaQnaMt.set("sysDivCd", sysDivCd);
	dmaQnaMt.set("priorNttYn", "N");
	dmaQnaMt.set("nttClsCd1", "");
};

scwin.deleteQnaLeft = function() {
	for(var i=0; i < qnaAtchfl.getWindow()._dltNttFile.getRowCount() ; i++) {
		qnaAtchfl.getWindow()._dltNttFile.deleteRow(i);
	}
	dmaQnaMt.set("rowStatus", "D");
	var requestData = {};
	requestData.data = dmaQnaMt.getJSON();
	requestData.data1 = qnaAtchfl.getWindow()._dltNttFile.getAllJSON();
	//requestData.data1 = [];

	var option = {
		action : "sc/ntt/saveNtt.do",
		reqData : requestData,
		success : "scwin.deleteQnaCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.deleteQnaCallback = function() {
	$("table.view").removeClass("table-on");
	utilLib.clearDcObj(dltQnaList);
	utilLib.clearDcObj(dltQnaReplaList);
	var requestData = {};
	requestData.data = {
		"bbsId":dmaQnaMt.get("bbsId"),
		"nttTit" : "",
		rnum:0,
		totalCount : 0,
		pageSize : comLib.PAGE_QNA_SIZE
	};

	var option = {
		action : "sc/ntt/retrieveQnaNtt.do",
		reqData : requestData,
		resData : "",
		success : "scwin.choiseQnaCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
* 게시물 조회후 콜백 로직을 수행한다.
*/
scwin.choiseQnaCallback = function(resBody) {
	replaTxt.setValue("");
	if (resBody.message.code == 'success') {
		dltQnaList.setJSON(resBody.dltQnaList, true);
		dltQnaReplaList.setJSON(resBody.dltQnaReplaList, true);
		if (dltQnaList.getRowCount() > 0) {
			var str = [];
			for(var i=0;i<dltQnaList.getRowCount();i++) {
				str.push("<div class=\"w2group text-group\">");
				str.push("<ul class=\"w2group \">");
				str.push("<li class=\"w2group \">");
				str.push("<div class=\"w2group talk\">");
				str.push("<a href=\"javascript:" + comLib.getFrameId($p) + "scwin.selectQna('"+dltQnaList.getCellData(i, "nttNo")+"');\" class=\"w2anchor2 \">");
				if (dltQnaList.getCellData(i, "nttClsNm1") != "") {
					str.push("[" + dltQnaList.getCellData(i, "nttClsNm1") + "]   ");
				}
				str.push(dltQnaList.getCellData(i, "nttTit"));
				str.push("</a>");
				str.push("<div class=\"w2group user\">");
				str.push("<img src=\"/resources/images/common/pic-c-qa.png\" class=\"w2image \">");
				str.push("<span class=\"w2span name\">"+dltQnaList.getCellData(i, "korname")+" ㅣ "+dltQnaList.getCellData(i, "dept")+" ㅣ " + dltQnaList.getCellData(i, "posit")+"</span>");
				str.push("<span class=\"w2span day\">"+dltQnaList.getCellData(i, "frstRegistDt")+"</span>");
				str.push("</div>");
				str.push("</div>");
				str.push("</il>");
				var dltQnaJson = dltQnaReplaList.getMatchedJSON("parntsNttNo", dltQnaList.getCellData(i, "nttNo"), true, 0, dltQnaReplaList.getRowCount());
				if (dltQnaReplaList.getMatchedJSON("parntsNttNo", dltQnaList.getCellData(i, "nttNo"), true, 0, dltQnaReplaList.getRowCount()) == "") {
					str.push("<li class=\"w2group de\">");
					str.push("<div class=\"w2group \">");
					str.push("<span class=\"w2span \">답변 대기중입니다.</span>");
					str.push("<a class=\"w2anchor2 \" href=\"javascript:" + comLib.getFrameId($p) + "scwin.selectQna('"+dltQnaList.getCellData(i, "nttNo")+"');\">답변하기</a>");
					str.push("</div>");
					str.push("</il>");
				} else {
					str.push("<li class=\"w2group re\">");
					for(var y=0;y<dltQnaJson.length;y++) {
						str.push("<div class=\"w2group \">");
						str.push("<a class=\"w2anchor2 \" href=\"javascript:" + comLib.getFrameId($p) + "scwin.selectQna('"+dltQnaList.getCellData(i, "nttNo")+"');\" class=\"w2anchor2 \">");
						str.push(dltQnaJson[y].nttCtnt);
						str.push("</a>");
						str.push("<div class=\"w2group user\">");
						str.push("<span class=\"w2span name\">"+dltQnaJson[y].korname+" ㅣ "+dltQnaJson[y].dept+" ㅣ " + dltQnaJson[y].posit+"</span>");
						str.push("<span class=\"w2span day\">"+dltQnaJson[y].frstRegistDt+"</span>");
						str.push("</div>");
						str.push("</div>");
					}
					str.push("</li>");
				}

				str.push("</ui>");
				str.push("</div>");
			}
			qnaDetail.render.innerHTML = str.join(""); 
		} else {
			qnaDetail.render.innerHTML = ""; 
		}
		if (saveQnaNttNo != "") {
			scwin.selectQna(saveQnaNttNo);
		}
	} else {
		alert("fail");
	}
};

scwin.btnSaveRepal_onclick = function() {
	// 입력값 셋팅
	scwin.repalStatus = "C";
	if (replaTxt.getValue() == "") {
		comLib.alert($p,  utilLib.getMessage("SCM.INFO.00004", "답변 내용 "));
		return false;
	}
	if (repalAtchfl.getWindow()._mpdRepalMultiAtchFile.getFileCount() > 0) {
		repalAtchfl.getWindow()._mpdRepalMultiAtchFile.startUpload();
	} else {
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveRepalConfirmCallback");
	}
};

/**
 * 저장처리
 */
scwin.saveRepalConfirmCallback = function() {
	//alert (11);
	comLib.NTT_NO = dmaQnaMt.get("nttNo");
	damReplaMng.set("rowStatus", "C");
	damReplaMng.set("parntsNttNo", dmaQnaMt.get("nttNo"));
	damReplaMng.set("nttNo", "");
	damReplaMng.set("bbsId", dmaQnaMt.get("bbsId"));
	damReplaMng.set("sysDivCd", dmaQnaMt.get("sysDivCd"));
	damReplaMng.set("nttClsCd1", dmaQnaMt.get("nttClsCd1"));
	damReplaMng.set("nttClsCd2", dmaQnaMt.get("nttClsCd2"));
	damReplaMng.set("nttTit", "답변 : "+dmaQnaMt.get(" nttTit"));
	damReplaMng.set("nttCtnt", replaTxt.getValue());
	damReplaMng.set("answerYn", "Y");
	damReplaMng.set("priorNttYn", "N");
	damReplaMng.set("useYn", "Y");

	//utilLib.clearDcObj(repalAtchfl.getWindow()._dltRepalFile);
	//repalAtchfl.getWindow()._dltRepalFile.setJSON(resBody.dltQnaList, true);
	var requestData = {};
	requestData.data = damReplaMng.getJSON();
	requestData.data1 = repalAtchfl.getWindow()._dltRepalFile.getModifiedJSON();
	//alert ("1" + JSON.stringify(requestData));
	//alert ("2" +	JSON.stringify(qnaAtchfl.getWindow()._dltNttFile.getAllJSON()));
	//requestData.data1 = [];
	var option = {
		action : "sc/ntt/saveNtt.do",
		reqData : requestData,
		resData : "",
		success : "scwin.saveQnaReplaCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.saveQnaReplaCallback = function(resBody) {
	utilLib.clearDcObj(dltQnaList);
	utilLib.clearDcObj(dltQnaReplaList);
	replaTxt.setValue("");
	utilLib.clearDcObj(repalAtchfl.getWindow()._dltRepalFile);
	scwin.choiseQna(txtQnaNo.getValue(), txtCnt.getValue());
};

/**
 * 첨부파일 다운로드
 * @param event
 * @return 첨부파일
 */
scwin.fileQnaDownload = function(atchflId, fileSeq) {
	if (atchflId != null && atchflId != '') {
		var dmaTest = {
			"atchflId" : atchflId,
			"fileSeq" : fileSeq
		};
		var xmlValue = JSON.stringify(dmaTest);
		// $w.download("/sc/file/downloadAtchFileOne.do", xmlValue, "get");
		comLib.downloadAtchfl("/sc/file/downloadAtchFileOne.do", xmlValue, "get");
	}
};

scwin.detailsQnaRepla = function(repNo) {
	btnSaveRepal.hide();
	btnUpdateRepal.show("inline-block");

	var dltQnaReplaJson = dltQnaReplaList.getMatchedJSON("nttNo", repNo, true, 0, dltQnaReplaList.getRowCount());

	replaTxt.setValue(dltQnaReplaJson[0].nttCtnt);

	damReplaMng.set("rowStatus", "U");
	damReplaMng.set("nttNo", dltQnaReplaJson[0].nttNo);
	damReplaMng.set("bbsId", dltQnaReplaJson[0].bbsId);
	damReplaMng.set("sysDivCd", dltQnaReplaJson[0].sysDivCd);
	damReplaMng.set("parntsNttNo", dltQnaReplaJson[0].parntsNttNo);
	damReplaMng.set("nttClsCd1", dltQnaReplaJson[0].nttClsCd1);
	damReplaMng.set("nttClsCd2", dltQnaReplaJson[0].nttClsCd2);
	damReplaMng.set("nttTit", dltQnaReplaJson[0].nttTit);
	damReplaMng.set("atchflId", dltQnaReplaJson[0].atchflId);
	damReplaMng.set("answerYn", dltQnaReplaJson[0].answerYn);
	damReplaMng.set("priorNttYn", dltQnaReplaJson[0].priorNttYn);
	damReplaMng.set("useYn", dltQnaReplaJson[0].useYn);

	utilLib.clearDcObj(repalAtchfl.getWindow()._dltRepalFile);
	var dltRepalFileListJson =  dltRepalFileList.getMatchedJSON("atchflId", dltQnaReplaJson[0].atchflId, true, 0, dltRepalFileList.getRowCount());
	repalAtchfl.getWindow()._dltRepalFile.setJSON(dltRepalFileListJson, true);
};

scwin.btnUpdateRepal_onclick = function() {
	// 입력값 셋팅
	scwin.repalStatus = "U";
	if (replaTxt.getValue() == "") {
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00004", "답변 내용 "));
		return false;
	}
	if (_mpdRepalMultiAtchFile.getFileCount() > 0) {
		_mpdRepalMultiAtchFile.startUpload();
	} else {
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "saveUpdateRepalConfirmCallback");
	}
};

/**
 * 저장처리
 */
scwin.saveUpdateRepalConfirmCallback = function() {
	comLib.NTT_NO = damReplaMng.get("parntsNttNo");
	damReplaMng.set("rowStatus", "U");
	damReplaMng.set("nttCtnt", replaTxt.getValue());
	var requestData = {};
	requestData.data = damReplaMng.getJSON();
	requestData.data1 = repalAtchfl.getWindow()._dltRepalFile.getModifiedJSON();
	//requestData.data1 = [];
	var option = {
		action : "sc/ntt/saveNtt.do",
		reqData : requestData,
		resData : "",
		success : "scwin.saveQnaReplaCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.deleteQnaRepla = function(repNo) {
	var requestData = {};
	requestData.data = {
		"nttNo" : repNo
	};

	var option = {
		action : "sc/ntt/deleteQnaRepla.do",
		reqData : requestData,
		success : "scwin.saveQnaCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

//신규버튼 클릭시
scwin.btnQnaAddList_onclick = function() {
	comLib.choiseQna(txtQnaNo.getValue(), txtCnt.getValue());
};

scwin.searchQnaBtn_onclick = function() {
	comLib.choiseQna(txtQnaNo.getValue(), 0);
};
